```

### Modern C++ 速查表

| 特性 | 示例 | 用途 |
|------|------|------|
| auto | auto x = compute(); | 自动类型推导 |
| 结构化绑定 | auto [x,y] = point; | 解构返回值 |
| if constexpr | if constexpr (is_float) | 编译期条件 |
| std::optional | optional<int> find(); | 可能无返回值 |
| std::variant | variant<int,string> v; | 类型安全联合 |
| std::string_view | void f(string_view s); | 零拷贝字符串 |
| 折叠表达式 | (args + ...); | 变参模板 |
| 智能指针 | unique_ptr/shared_ptr | RAII 内存管理 |
### 练习
1. 用 unique_ptr 实现一个机器人关节链（Joint → Link → Joint → ...）
2. 用 lambda + std::transform 把关节角度从弧度批量转换为角度
3. 实现一个带 std::optional 返回值的碰撞检测函数

### 参考答案

**1. 用 unique_ptr 实现机器人关节链**

```cpp
#include <memory>
#include <string>
#include <iostream>
#include <vector>

struct Joint {
    std::string name;
    double angle = 0.0;  // 关节角度 (rad)
    double limit_min, limit_max;

    Joint(std::string n, double lo, double hi)
        : name(std::move(n)), limit_min(lo), limit_max(hi) {}
};

struct Link {
    std::string name;
    double length;  // 连杆长度 (m)
    std::unique_ptr<Joint> child_joint;  // 下一个关节 (独占所有权)
    std::unique_ptr<Link> child_link;    // 下一个连杆

    Link(std::string n, double len) : name(std::move(n)), length(len) {}

    void attach(std::unique_ptr<Joint> j, std::unique_ptr<Link> l) {
        child_joint = std::move(j);  // 转移所有权
        child_link = std::move(l);
    }
};

class KinematicChain {
public:
    KinematicChain() {
        // 构建: base → joint1 → link1 → joint2 → link2 → ...
        auto link2 = std::make_unique<Link>("link2", 0.3);
        auto joint2 = std::make_unique<Joint>("joint2", -M_PI, M_PI);

        auto link1 = std::make_unique<Link>("link1", 0.4);
        link1->attach(std::move(joint2), std::move(link2));

        base_joint_ = std::make_unique<Joint>("joint1", -M_PI, M_PI);
        base_link_ = std::move(link1);
    }

    void print() const {
        std::cout << base_joint_->name;
        Link* link = base_link_.get();
        while (link) {
            std::cout << " -> " << link->name;
            if (link->child_joint)
                std::cout << " -> " << link->child_joint->name;
            link = link->child_link.get();
        }
        std::cout << std::endl;
    }
    // 离开作用域时, 所有 Joint 和 Link 自动释放!

private:
    std::unique_ptr<Joint> base_joint_;
    std::unique_ptr<Link> base_link_;
};

// KinematicChain chain;
// chain.print();  // joint1 -> link1 -> joint2 -> link2
```

**2. Lambda + std::transform 弧度转角度**

```cpp
#include <vector>
#include <algorithm>
#include <cmath>
#include <iostream>

int main() {
    std::vector<double> radians = {0.0, M_PI/6, M_PI/4, M_PI/3, M_PI/2, M_PI};
    std::vector<double> degrees(radians.size());

    // lambda + transform: 批量转换
    std::transform(radians.begin(), radians.end(), degrees.begin(),
        [](double rad) { return rad * 180.0 / M_PI; });

    // 输出
    for (size_t i = 0; i < radians.size(); ++i) {
        std::cout << radians[i] << " rad = " << degrees[i] << " deg" << std::endl;
    }
    // 0 rad = 0 deg
    // 0.5236 rad = 30 deg
    // 0.7854 rad = 45 deg
    // ...

    // 更 Modern 的写法 (C++20 ranges)
    // auto deg_view = radians | std::views::transform(
    //     [](double r) { return r * 180.0 / M_PI; });

    return 0;
}
```

**3. std::optional 碰撞检测**

```cpp
#include <optional>
#include <cmath>
#include <iostream>
#include <string>

struct CollisionInfo {
    std::string link_name;   // 碰撞的连杆
    double penetration;      // 穿透深度 (m)
    double contact_point[3]; // 接触点坐标
};

// 返回 optional: 有碰撞返回 CollisionInfo, 无碰撞返回 nullopt
std::optional<CollisionInfo> check_collision(
    const double* joint_angles, int n_joints, 
    const double* obstacle_pos, double obstacle_radius) {

    // 简化的碰撞检测: 检查每个关节到障碍物的距离
    for (int i = 0; i < n_joints; ++i) {
        double link_x = 0.3 * (i+1) * cos(joint_angles[i]);
        double link_y = 0.3 * (i+1) * sin(joint_angles[i]);
        double link_z = 0.5;

        double dist = sqrt(
            pow(link_x - obstacle_pos[0], 2) +
            pow(link_y - obstacle_pos[1], 2) +
            pow(link_z - obstacle_pos[2], 2));

        if (dist < obstacle_radius) {
            return CollisionInfo{
                "link_" + std::to_string(i),
                obstacle_radius - dist,
                {link_x, link_y, link_z}
            };
        }
    }
    return std::nullopt;  // 无碰撞
}

